def range_summary(nums):
    if not nums:
        return ''
    prev, result = None, []
    for n in sorted(set(nums)):
        if prev is not None and n - 1 == prev:
            result[-1] = f'{result[-1]} {n}'
        elif prev is not None:
            result.append(f'{prev}-{n}')
        else:
            result.append(str(n))
        prev = n
    return ', '.join(result)
